import { impuestos } from "@/constants/impuestos";
import type {
  CotizacionWorkflowDraft,
  CotizacionWorkflowItem,
  CotizacionWorkflowRecord,
  EstadoCotizacionWorkflow,
  MaterialCotizacionWorkflow,
} from "@/types/cotizacion-workflow";

const DEFAULT_FLETE = 79540;

const BASE_PRICE_BY_LINEA: Record<string, number> = {
  S60: 118000,
  ANDES: 148000,
  SLIDING: 340000,
  DVH: 280000,
  REHAU: 198000,
  VEKA: 214000,
  SALAMANDER: 228000,
};

type EstimateItemInput = {
  id?: string;
  material: MaterialCotizacionWorkflow;
  linea: string;
  color: string;
  vidrio: string;
  ancho: number;
  alto: number;
  cantidad?: number;
};

type CreateCotizacionRecordInput = {
  draft: CotizacionWorkflowDraft;
  estado: EstadoCotizacionWorkflow;
  existingId?: string;
  existingCode?: string;
  createdAt?: string;
  now?: Date;
};

function getBasePrice(linea: string, material: MaterialCotizacionWorkflow) {
  if (BASE_PRICE_BY_LINEA[linea]) {
    return BASE_PRICE_BY_LINEA[linea];
  }

  return material === "pvc" ? 190000 : 118000;
}

function formatSequentialCode(sequence: string) {
  return `COT-${sequence.padStart(6, "0")}`;
}

export function buildCotizacionCode(now = new Date()) {
  const value = Number(
    `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, "0")}${String(
      now.getDate()
    ).padStart(2, "0")}${String(now.getHours()).padStart(2, "0")}${String(
      now.getMinutes()
    ).padStart(2, "0")}${String(now.getSeconds()).padStart(2, "0")}`
  );

  return formatSequentialCode(String(value).slice(-6));
}

export function buildCotizacionId(now = new Date()) {
  return `cot-${now.getTime()}`;
}

export function formatCotizacionDate(date: string) {
  return new Intl.DateTimeFormat("es-CL", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  }).format(new Date(date));
}

export function estimateCotizacionItem(
  input: EstimateItemInput
): CotizacionWorkflowItem {
  const ancho = Number(input.ancho) || 0;
  const alto = Number(input.alto) || 0;
  const cantidad = Number(input.cantidad) > 0 ? Number(input.cantidad) : 1;
  const areaM2 = Number((((ancho / 1000) * (alto / 1000)) || 0).toFixed(2));
  const basePrice = getBasePrice(input.linea, input.material);
  const precioUnitario = Math.round(areaM2 * basePrice);
  const precioTotal = precioUnitario * cantidad;
  const materialLabel = input.material === "aluminio" ? "Aluminio" : "PVC";

  return {
    id: input.id ?? `item-${input.linea.toLowerCase()}-${ancho}-${alto}-${cantidad}`,
    material: input.material,
    linea: input.linea,
    color: input.color,
    vidrio: input.vidrio,
    ancho,
    alto,
    cantidad,
    areaM2,
    precioUnitario,
    precioTotal,
    descripcion: `${materialLabel} ${input.linea} · ${input.color} · ${input.vidrio}`,
  };
}

export function calculateCotizacionWorkflowTotals(
  items: CotizacionWorkflowItem[],
  descuentoPct = 0,
  flete = DEFAULT_FLETE
) {
  const subtotal = items.reduce((accumulator, item) => {
    return accumulator + item.precioTotal;
  }, 0);

  const descuentoValor = Math.round(subtotal * (descuentoPct / 100));
  const neto = subtotal - descuentoValor;
  const iva = Math.round(neto * impuestos.iva);
  const total = neto + iva + flete;

  return {
    subtotal,
    descuentoValor,
    neto,
    iva,
    flete,
    total,
  };
}

export function createCotizacionWorkflowDraft(): CotizacionWorkflowDraft {
  return {
    clienteNombre: "",
    clienteTelefono: "",
    obra: "",
    direccion: "",
    validez: "7 dias",
    descuentoPct: 0,
    observaciones: "",
    items: [],
  };
}

export function createCotizacionRecord(
  input: CreateCotizacionRecordInput
): CotizacionWorkflowRecord {
  const now = input.now ?? new Date();
  const timestamp = now.toISOString();
  const totals = calculateCotizacionWorkflowTotals(
    input.draft.items,
    input.draft.descuentoPct
  );

  return {
    id: input.existingId ?? buildCotizacionId(now),
    codigo: input.existingCode ?? buildCotizacionCode(now),
    clienteNombre: input.draft.clienteNombre.trim(),
    clienteTelefono: input.draft.clienteTelefono.trim(),
    obra: input.draft.obra.trim(),
    direccion: input.draft.direccion.trim(),
    validez: input.draft.validez,
    descuentoPct: input.draft.descuentoPct,
    observaciones: input.draft.observaciones.trim(),
    estado: input.estado,
    createdAt: input.createdAt ?? timestamp,
    updatedAt: timestamp,
    items: input.draft.items,
    ...totals,
  };
}

function createSeedRecord(input: {
  id: string;
  codigo: string;
  clienteNombre: string;
  clienteTelefono: string;
  obra: string;
  direccion: string;
  createdAt: string;
  estado: EstadoCotizacionWorkflow;
  items: EstimateItemInput[];
  descuentoPct?: number;
  observaciones?: string;
  validez?: string;
}) {
  const draft: CotizacionWorkflowDraft = {
    clienteNombre: input.clienteNombre,
    clienteTelefono: input.clienteTelefono,
    obra: input.obra,
    direccion: input.direccion,
    validez: input.validez ?? "15 dias",
    descuentoPct: input.descuentoPct ?? 0,
    observaciones: input.observaciones ?? "",
    items: input.items.map((item, index) =>
      estimateCotizacionItem({
        ...item,
        id: `seed-item-${input.id}-${index + 1}`,
      })
    ),
  };

  return createCotizacionRecord({
    draft,
    estado: input.estado,
    existingId: input.id,
    existingCode: input.codigo,
    createdAt: input.createdAt,
    now: new Date(input.createdAt),
  });
}

